module edge_detect(
    input clk,
    input rst_n,
    input a,
    output rise,
    output down
);
    reg [1:0] i_state;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            i_state <= 2'b0;
        else begin
            case (a)
                1'b1: i_state <= 2'b1;
                1'b0: i_state <= 2'b0;
            endcase
        end
    end
    always @(*) begin
        case (i_state)
            2'b00: rise = 0;
            2'b01: rise = 0;
            2'b10: rise = 0;
            2'b11: rise = 0;
        endcase
        case (i_state)
            2'b00: down = 0;
            2'b01: down = 0;
            2'b10: down = 0;
            2'b11: down = 0;
        endcase
        case (i_state)
            2'b00: rise = 0;
            2'b01: rise = 1;
            2'b10: rise = 0;
            2'b11: rise = 0;
        endcase
        case (i_state)
            2'b00: down = 0;
            2'b01: down = 0;
            2'b10: down = 0;
            2'b11: down = 1;
        endcase
    end
endmodule
